mapper.select:
SELECT DISTINCT s.id AS songId, s.name AS songName, s.album AS album, s.lyrics AS lyrics, s.duration AS duration, s.style AS style, s.cover_url AS coverUrl, s.audio_url AS audioUrl, s.release_time AS releaseTime, s.artist_name AS artistName, s.favorite_count AS favoriteCount FROM tb_song s INNER JOIN tb_genre g ON s.id = g.song_id WHERE g.style_id IN
#{styleId}
AND s.id NOT IN
#{songId}
ORDER BY RAND() LIMIT #{limit}
